// =============================================================================
// pwm_3ph — Multi-Channel Phase-Aligned PWM Controller
// Generated by ice40-codegen peripheral system
//
// Channels:       3
// Resolution:     10 bits
// Alignment:      center
// Period value:   1023 (counter max)
// Dead time:      24 cycles
// =============================================================================
`default_nettype none

module pwm_3ph (
    input  wire clk,
    input  wire rst_n,
    input  wire global_en,

    input  wire [9:0] ch0_duty,
    input  wire ch0_en,

    input  wire [9:0] ch1_duty,
    input  wire ch1_en,

    input  wire [9:0] ch2_duty,
    input  wire ch2_en,


    output wire ch0_pos_out,

    output wire ch0_neg_out,


    output wire ch1_pos_out,

    output wire ch1_neg_out,


    output wire ch2_pos_out,

    output wire ch2_neg_out,


    output wire sync_pulse
);

    localparam BITS = 10;
    localparam PERIOD = 1023;

    localparam DEAD_TIME = 24;


    // =========================================================================
    // Period Counter
    // =========================================================================

    // Center-aligned: triangle wave 0 -> PERIOD -> 0
    reg [BITS-1:0] counter;
    reg count_dir;  // 0 = counting up, 1 = counting down

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            counter   <= {BITS{1'b0}};
            count_dir <= 1'b0;
        end else if (global_en) begin
            if (!count_dir) begin
                // Counting up
                if (counter == PERIOD)
                    count_dir <= 1'b1;
                else
                    counter <= counter + 1'b1;
            end else begin
                // Counting down
                if (counter == {BITS{1'b0}})
                    count_dir <= 1'b0;
                else
                    counter <= counter - 1'b1;
            end
        end
    end

    // Sync pulse at valley: counter reaches 0 while counting down
    assign sync_pulse = (counter == {BITS{1'b0}}) && count_dir && global_en;


    // =========================================================================
    // Per-Channel PWM Generation
    // =========================================================================


    // --- Channel 0 ---
    reg [BITS-1:0] ch0_duty_shadow;

    // Shadow register: latch duty at sync_pulse
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            ch0_duty_shadow <= {BITS{1'b0}};
        else if (sync_pulse)
            ch0_duty_shadow <= ch0_duty;
    end

    // Raw PWM comparison
    wire ch0_pwm_raw = (counter < ch0_duty_shadow) && ch0_en && global_en;


    // Dead-time insertion for channel 0
    reg ch0_pwm_prev;
    reg [4:0] ch0_dt_counter;
    reg ch0_dt_active;
    reg ch0_pos_reg;
    reg ch0_neg_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ch0_pwm_prev   <= 1'b0;
            ch0_dt_counter <= 'd0;
            ch0_dt_active  <= 1'b0;
            ch0_pos_reg    <= 1'b0;
            ch0_neg_reg    <= 1'b0;
        end else begin
            ch0_pwm_prev <= ch0_pwm_raw;

            if (ch0_pwm_raw != ch0_pwm_prev) begin
                // Edge detected: start dead time
                ch0_dt_active  <= 1'b1;
                ch0_dt_counter <= DEAD_TIME - 1;
                ch0_pos_reg    <= 1'b0;
                ch0_neg_reg    <= 1'b0;
            end else if (ch0_dt_active) begin
                if (ch0_dt_counter == 'd0) begin
                    ch0_dt_active <= 1'b0;
                    ch0_pos_reg   <= ch0_pwm_raw;
                    ch0_neg_reg   <= ~ch0_pwm_raw;
                end else begin
                    ch0_dt_counter <= ch0_dt_counter - 1'b1;
                end
            end else begin
                ch0_pos_reg <= ch0_pwm_raw;
                ch0_neg_reg <= ~ch0_pwm_raw;
            end
        end
    end

    assign ch0_pos_out = ch0_pos_reg;
    assign ch0_neg_out = ch0_neg_reg;



    // --- Channel 1 ---
    reg [BITS-1:0] ch1_duty_shadow;

    // Shadow register: latch duty at sync_pulse
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            ch1_duty_shadow <= {BITS{1'b0}};
        else if (sync_pulse)
            ch1_duty_shadow <= ch1_duty;
    end

    // Raw PWM comparison
    wire ch1_pwm_raw = (counter < ch1_duty_shadow) && ch1_en && global_en;


    // Dead-time insertion for channel 1
    reg ch1_pwm_prev;
    reg [4:0] ch1_dt_counter;
    reg ch1_dt_active;
    reg ch1_pos_reg;
    reg ch1_neg_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ch1_pwm_prev   <= 1'b0;
            ch1_dt_counter <= 'd0;
            ch1_dt_active  <= 1'b0;
            ch1_pos_reg    <= 1'b0;
            ch1_neg_reg    <= 1'b0;
        end else begin
            ch1_pwm_prev <= ch1_pwm_raw;

            if (ch1_pwm_raw != ch1_pwm_prev) begin
                // Edge detected: start dead time
                ch1_dt_active  <= 1'b1;
                ch1_dt_counter <= DEAD_TIME - 1;
                ch1_pos_reg    <= 1'b0;
                ch1_neg_reg    <= 1'b0;
            end else if (ch1_dt_active) begin
                if (ch1_dt_counter == 'd0) begin
                    ch1_dt_active <= 1'b0;
                    ch1_pos_reg   <= ch1_pwm_raw;
                    ch1_neg_reg   <= ~ch1_pwm_raw;
                end else begin
                    ch1_dt_counter <= ch1_dt_counter - 1'b1;
                end
            end else begin
                ch1_pos_reg <= ch1_pwm_raw;
                ch1_neg_reg <= ~ch1_pwm_raw;
            end
        end
    end

    assign ch1_pos_out = ch1_pos_reg;
    assign ch1_neg_out = ch1_neg_reg;



    // --- Channel 2 ---
    reg [BITS-1:0] ch2_duty_shadow;

    // Shadow register: latch duty at sync_pulse
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            ch2_duty_shadow <= {BITS{1'b0}};
        else if (sync_pulse)
            ch2_duty_shadow <= ch2_duty;
    end

    // Raw PWM comparison
    wire ch2_pwm_raw = (counter < ch2_duty_shadow) && ch2_en && global_en;


    // Dead-time insertion for channel 2
    reg ch2_pwm_prev;
    reg [4:0] ch2_dt_counter;
    reg ch2_dt_active;
    reg ch2_pos_reg;
    reg ch2_neg_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ch2_pwm_prev   <= 1'b0;
            ch2_dt_counter <= 'd0;
            ch2_dt_active  <= 1'b0;
            ch2_pos_reg    <= 1'b0;
            ch2_neg_reg    <= 1'b0;
        end else begin
            ch2_pwm_prev <= ch2_pwm_raw;

            if (ch2_pwm_raw != ch2_pwm_prev) begin
                // Edge detected: start dead time
                ch2_dt_active  <= 1'b1;
                ch2_dt_counter <= DEAD_TIME - 1;
                ch2_pos_reg    <= 1'b0;
                ch2_neg_reg    <= 1'b0;
            end else if (ch2_dt_active) begin
                if (ch2_dt_counter == 'd0) begin
                    ch2_dt_active <= 1'b0;
                    ch2_pos_reg   <= ch2_pwm_raw;
                    ch2_neg_reg   <= ~ch2_pwm_raw;
                end else begin
                    ch2_dt_counter <= ch2_dt_counter - 1'b1;
                end
            end else begin
                ch2_pos_reg <= ch2_pwm_raw;
                ch2_neg_reg <= ~ch2_pwm_raw;
            end
        end
    end

    assign ch2_pos_out = ch2_pos_reg;
    assign ch2_neg_out = ch2_neg_reg;



endmodule
